namespace sv_f98a5263999c45189d80e318985f3959.Services;

/// <summary>
/// Scoped service holding the current warehouse selection.
/// In Blazor Server, scoped = per-circuit = per-user isolation.
/// </summary>
public class WarehouseState
{
    public static readonly (string Id, string Name)[] Warehouses =
    [
        ("WH-001", "Warehouse A — East"),
        ("WH-002", "Warehouse B — West"),
        ("WH-003", "Warehouse C — North"),
        ("WH-004", "Warehouse D — South"),
    ];

    public string CurrentWarehouseId { get; private set; } = Warehouses[0].Id;
    public string CurrentWarehouseName { get; private set; } = Warehouses[0].Name;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        var match = Warehouses.FirstOrDefault(w => w.Id == warehouseId);
        if (match == default) return;

        CurrentWarehouseId = match.Id;
        CurrentWarehouseName = match.Name;
        OnChange?.Invoke();
    }
}

