@page "/dashboard"
@using sv_f98a5263999c45189d80e318985f3959.Services
@rendermode InteractiveServer
@inject WarehouseState WarehouseState
@inject InventoryAlertService InventoryAlertService
@inject AlertState AlertState
@implements IDisposable

<PageTitle>Dashboard — @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>
<p class="text-muted">
    Managing: <strong>@WarehouseState.CurrentWarehouseName</strong>
    <span class="text-secondary">(@WarehouseState.CurrentWarehouseId)</span>
</p>

<div class="row g-4 mt-2">
    <div class="col-md-4">
        <div class="card border-danger">
            <div class="card-body text-center">
                <h5 class="card-title text-danger">Low-Stock Alerts</h5>
                <p class="display-4 fw-bold text-danger">@_lowStockCount</p>
                <p class="text-muted mb-0">items below minimum level</p>
            </div>
            <div class="card-footer text-muted text-center">
                Refreshes every 10 seconds
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Current Site</h5>
                <p class="display-6">@WarehouseState.CurrentWarehouseName</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Status</h5>
                <p class="display-6 @(_lowStockCount > 5 ? "text-warning" : "text-success")">
                    @(_lowStockCount > 5 ? "⚠ Attention" : "✓ Normal")
                </p>
            </div>
        </div>
    </div>
</div>

@code {
    private int _lowStockCount;
    private Timer? _pollingTimer;

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += OnWarehouseChanged;

        await PollAlerts();
        StartPolling();
    }

    private void StartPolling()
    {
        _pollingTimer?.Dispose();
        _pollingTimer = new Timer(async _ =>
        {
            await PollAlerts();
            await InvokeAsync(StateHasChanged);
        }, null, TimeSpan.FromSeconds(10), TimeSpan.FromSeconds(10));
    }

    private async Task PollAlerts()
    {
        _lowStockCount = await InventoryAlertService.GetLowStockCountAsync(
            WarehouseState.CurrentWarehouseId);
        AlertState.Update(_lowStockCount);
    }

    private async void OnWarehouseChanged()
    {
        // Immediately refresh on warehouse switch.
        await PollAlerts();
        await InvokeAsync(StateHasChanged);

        // Restart the polling interval so the next tick is a full 10s out.
        StartPolling();
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        _pollingTimer?.Dispose();
    }
}

